Leak pattern 1 -- overwritten pointer:
  p = malloc(A);  /* block A allocated */
  p = malloc(B);  /* block A leaked! */

Leak pattern 2 -- early return:
  p = malloc(A);
  if (error) return;  /* A leaked! */
  free(p);

Goto cleanup pattern (prevention):
  int func() {
    int *a = NULL, *b = NULL;
    a = malloc(...);
    if (!a) goto cleanup;
    b = malloc(...);
    if (!b) goto cleanup;
    /* use a and b */
  cleanup:
    free(b);  /* free(NULL) is safe */
    free(a);
    return result;
  }

