#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* BAD: memory leak on early return */
int process_bad(const char *input) {
    char *buf = malloc(strlen(input) + 1);
    if (!buf) return -1;
    strcpy(buf, input);

    if (strlen(buf) < 3) {
        return -2; /* LEAK: buf not freed! */
    }

    printf("Processed: %s\n", buf);
    free(buf);
    return 0;
}

/* GOOD: goto cleanup pattern */
int process_good(const char *input) {
    int result = 0;
    char *buf = NULL;
    char *upper = NULL;

    buf = malloc(strlen(input) + 1);
    if (!buf) { result = -1; goto cleanup; }
    strcpy(buf, input);

    upper = malloc(strlen(input) + 1);
    if (!upper) { result = -1; goto cleanup; }

    for (size_t i = 0; input[i]; i++) {
        upper[i] = (input[i] >= 'a' && input[i] <= 'z')
                   ? input[i] - 32 : input[i];
    }
    upper[strlen(input)] = '\0';

    if (strlen(buf) < 3) {
        result = -2;
        goto cleanup; /* both buf and upper freed */
    }

    printf("Original: %s, Upper: %s\n", buf, upper);

cleanup:
    free(upper); /* free(NULL) is safe */
    free(buf);
    return result;
}

int main(void) {
    process_good("hello");
    process_good("hi"); /* short input, early exit but no leak */
    return 0;
}

