#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Simple fixed-size memory pool to avoid fragmentation */
#define POOL_BLOCK_SIZE 64
#define POOL_BLOCK_COUNT 10

typedef struct {
    char memory[POOL_BLOCK_SIZE * POOL_BLOCK_COUNT];
    int used[POOL_BLOCK_COUNT]; /* 0 = free, 1 = used */
} MemPool;

void pool_init(MemPool *pool) {
    memset(pool->used, 0, sizeof(pool->used));
}

void *pool_alloc(MemPool *pool) {
    for (int i = 0; i < POOL_BLOCK_COUNT; i++) {
        if (!pool->used[i]) {
            pool->used[i] = 1;
            return pool->memory + (i * POOL_BLOCK_SIZE);
        }
    }
    return NULL; /* pool exhausted */
}

void pool_free(MemPool *pool, void *ptr) {
    if (!ptr) return;
    ptrdiff_t offset = (char *)ptr - pool->memory;
    int index = (int)(offset / POOL_BLOCK_SIZE);
    if (index >= 0 && index < POOL_BLOCK_COUNT) {
        pool->used[index] = 0;
    }
}

int main(void) {
    MemPool pool;
    pool_init(&pool);

    /* Allocate from pool -- no fragmentation */
    int *a = (int *)pool_alloc(&pool);
    int *b = (int *)pool_alloc(&pool);
    int *c = (int *)pool_alloc(&pool);

    *a = 10; *b = 20; *c = 30;
    printf("%d %d %d\n", *a, *b, *c); /* 10 20 30 */

    pool_free(&pool, b); /* free middle block */
    int *d = (int *)pool_alloc(&pool); /* reuses b's slot */
    *d = 40;
    printf("%d\n", *d); /* 40 */

    /* No fragmentation: all blocks are the same size */
    printf("Block size: %d bytes\n", POOL_BLOCK_SIZE);

    return 0;
}

