#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct FreeNode {
    struct FreeNode *next;
} FreeNode;

typedef struct {
    void *memory;       /* raw block */
    FreeNode *free_list; /* head of free list */
    size_t block_size;  /* size of each slot */
    size_t count;       /* total number of slots */
} MemPool;

int pool_create(MemPool *pool, size_t block_size, size_t count) {
    /* Ensure block_size can hold a FreeNode pointer */
    if (block_size < sizeof(FreeNode)) {
        block_size = sizeof(FreeNode);
    }
    pool->block_size = block_size;
    pool->count = count;
    pool->memory = malloc(block_size * count);
    if (!pool->memory) return -1;

    /* Build free list: chain all blocks together */
    pool->free_list = NULL;
    for (size_t i = 0; i < count; i++) {
        FreeNode *node = (FreeNode *)((char *)pool->memory + i * block_size);
        node->next = pool->free_list;
        pool->free_list = node;
    }
    return 0;
}

void *pool_alloc(MemPool *pool) {
    if (!pool->free_list) return NULL; /* exhausted */
    FreeNode *block = pool->free_list;
    pool->free_list = block->next;
    return (void *)block;
}

void pool_free(MemPool *pool, void *ptr) {
    if (!ptr) return;
    FreeNode *node = (FreeNode *)ptr;
    node->next = pool->free_list;
    pool->free_list = node;
}

void pool_destroy(MemPool *pool) {
    free(pool->memory);
    pool->memory = NULL;
    pool->free_list = NULL;
}

/* Example: pool of fixed-size structs */
typedef struct { int x, y; } Point;

int main(void) {
    MemPool pool;
    pool_create(&pool, sizeof(Point), 100);

    Point *p1 = (Point *)pool_alloc(&pool);
    Point *p2 = (Point *)pool_alloc(&pool);
    p1->x = 10; p1->y = 20;
    p2->x = 30; p2->y = 40;
    printf("p1=(%d,%d) p2=(%d,%d)\n", p1->x, p1->y, p2->x, p2->y);

    pool_free(&pool, p1); /* O(1) */

    Point *p3 = (Point *)pool_alloc(&pool); /* reuses p1's slot */
    p3->x = 50; p3->y = 60;
    printf("p3=(%d,%d)\n", p3->x, p3->y);

    pool_destroy(&pool);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

typedef struct Node { struct Node *next; } Node;

typedef struct {
    void *mem;
    Node *free_list;
} Pool;

void pool_init(Pool *p, size_t blk, size_t n) {
    p->mem = malloc(blk * n);
    p->free_list = NULL;
    for (size_t i = 0; i < n; i++) {
        Node *nd = (Node *)((char *)p->mem + i * blk);
        nd->next = p->free_list;
        p->free_list = nd;
