        /* Verify alignment */
        if ((uintptr_t)aligned % alignment == 0) {
            printf("Correctly aligned to %zu bytes\n", alignment);
        }

        /* Use for SIMD-friendly data */
        for (int i = 0; i < 16; i++) {
            aligned[i] = (float)i;
        }
        printf("aligned[0]=%.0f aligned[15]=%.0f\n",
               aligned[0], aligned[15]);

        free(aligned); /* normal free works */
    }

    /* POSIX alternative: posix_memalign */
    void *posix_ptr = NULL;
    if (posix_memalign(&posix_ptr, 32, 128) == 0) {
        printf("posix_memalign: %p (mod 32 = %zu)\n",
               posix_ptr, (uintptr_t)posix_ptr % 32);
        free(posix_ptr);
    }

    return 0;
}

