/* Method 1: Array of pointers */
int **alloc_2d_method1(int rows, int cols) {
    int **arr = malloc(sizeof(int *) * rows);
    if (!arr) return NULL;
    for (int i = 0; i < rows; i++) {
        arr[i] = malloc(sizeof(int) * cols);
        if (!arr[i]) {
            /* cleanup on failure */
            for (int j = 0; j < i; j++) free(arr[j]);
            free(arr);
            return NULL;
        }
    }
    return arr;
}

void free_2d_method1(int **arr, int rows) {
    for (int i = 0; i < rows; i++) free(arr[i]);
    free(arr);
}

/* Method 2: Contiguous block with row pointers */
int **alloc_2d_method2(int rows, int cols) {
    int **arr = malloc(sizeof(int *) * rows);
    int *data = malloc(sizeof(int) * rows * cols);
    if (!arr || !data) { free(arr); free(data); return NULL; }
    for (int i = 0; i < rows; i++) {
        arr[i] = data + i * cols;
    }
    return arr;
}

void free_2d_method2(int **arr) {
    free(arr[0]); /* free the contiguous data block */
    free(arr);    /* free the row pointer array */
}

/* Method 3: Flat array */
int *alloc_2d_flat(int rows, int cols) {
    return malloc(sizeof(int) * rows * cols);
}

