#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Best practice: SAFE_FREE macro */
#define SAFE_FREE(p) do { free(p); (p) = NULL; } while(0)

/* Best practice: sizeof(*p) pattern */
int *create_array(int count) {
    int *arr = calloc(count, sizeof(*arr)); /* calloc: zeroed + overflow check */
    if (!arr) {
        perror("calloc");
        return NULL;
    }
    return arr; /* caller owns and must free */
}

/* Best practice: goto-cleanup pattern */
int process_data(int n) {
    int result = -1;
    int *buffer = NULL;
    char *name = NULL;

    /* Initialize all pointers to NULL */
    buffer = malloc(sizeof(*buffer) * n);
    if (!buffer) goto cleanup;

    name = malloc(256);
    if (!name) goto cleanup;

    /* ... process data ... */
    for (int i = 0; i < n; i++) buffer[i] = i;
    snprintf(name, 256, "result_%d", n);
    printf("%s: first=%d last=%d\n", name, buffer[0], buffer[n-1]);

    result = 0; /* success */

cleanup:
    SAFE_FREE(name);   /* free(NULL) is safe */
    SAFE_FREE(buffer);
    return result;
}

/* Best practice: create/destroy pairs */
typedef struct {
    int *data;
    int size;
} IntVector;

IntVector *vector_create(int size) {
    IntVector *v = malloc(sizeof(*v));
    if (!v) return NULL;
    v->data = calloc(size, sizeof(*v->data));
    if (!v->data) { free(v); return NULL; }
    v->size = size;
    return v;
}

void vector_destroy(IntVector *v) {
    if (v) {
        free(v->data);
        free(v);
    }
}

int main(void) {
    /* Using create/destroy pattern */
    IntVector *v = vector_create(5);
    if (v) {
        for (int i = 0; i < v->size; i++) v->data[i] = i * 10;
        printf("v[2] = %d\n", v->data[2]); /* 20 */
        vector_destroy(v);
    }

    /* Using goto-cleanup pattern */
    process_data(10);

    /* Using safe array creation */
    int *arr = create_array(5);
    if (arr) {
        printf("zeroed: %d\n", arr[0]); /* 0 */
        SAFE_FREE(arr);
    }

    return 0;
}

